INSERT INTO `wp_comments` (`comment_ID`, `comment_post_ID`, `comment_author`, `comment_author_email`, `comment_author_url`, `comment_author_IP`, `comment_date`, `comment_date_gmt`, `comment_content`, `comment_karma`, `comment_approved`, `comment_agent`, `comment_type`, `comment_parent`, `user_id`) VALUES
(2, 1, 'A WordPress Commenter', 'wapuu@wordpress.example', 'https://wordpress.org/', '', '2021-12-14 20:58:09', '2021-12-14 20:58:09', 'Hi, this is a comment.\nTo get started with moderating, editing, and deleting comments, please visit the Comments screen in the dashboard.\nCommenter avatars come from <a href=\"https://gravatar.com\" rel=\"nofollow ugc\">Gravatar</a>.', 0, '1', '', 'comment', 0, 0),
(3, 100, 'Michael', 'hq@creativethemes.com', 'https://startersites.io/blocksy/garderobe', '92.115.181.73', '2021-12-23 22:48:09', '2021-12-23 22:48:09', 'Convallis tellus id interdum velit laoreet id donec ultrices tincidunt.', 0, '1', '', 'review', 0, 0),
(4, 523, 'Michael', 'hq@creativethemes.com', 'https://startersites.io/blocksy/garderobe', '92.115.181.73', '2021-12-23 22:48:42', '2021-12-23 22:48:42', 'Turpis cursus in hac habitasse platea dictumst quisque sagittis. Amet mauris commodo quis imperdiet.', 0, '1', '', 'review', 0, 0),
(5, 523, 'Michael', 'hq@creativethemes.com', 'https://startersites.io/blocksy/garderobe', '188.237.250.238', '2021-12-24 08:40:44', '2021-12-24 08:40:44', 'Orci porta non pulvinar neque laoreet suspendisse. Turpis cursus in hac habitasse platea dictumst quisque sagittis.', 0, '1', '', 'review', 0, 0),
(6, 527, 'Michael', 'hq@creativethemes.com', 'https://startersites.io/blocksy/garderobe', '92.115.181.73', '2021-12-23 22:47:37', '2021-12-23 22:47:37', 'Auctor elit sed vulputate mi sit amet mauris commodo. Sed felis eget velit aliquet sagittis id consectetur purus ut. Imperdiet proin fermentum leo vel. Vestibulum sed arcu non odio.', 0, '1', '', 'review', 0, 0),
(7, 527, 'Michael', 'hq@creativethemes.com', 'https://startersites.io/blocksy/garderobe', '188.237.250.238', '2021-12-24 08:41:17', '2021-12-24 08:41:17', 'Feugiat in ante metus dictum at tempor commodo ullamcorper.', 0, '1', '', 'review', 0, 0),
(8, 529, 'Michael', 'hq@creativethemes.com', 'https://startersites.io/blocksy/garderobe', '92.115.181.73', '2021-12-23 22:50:46', '2021-12-23 22:50:46', 'Gravida arcu ac tortor dignissim convallis aenean et tortor at. Purus ut faucibus pulvinar elementum integer enim neque volutpat ac.', 0, '1', '', 'review', 0, 0),
(9, 532, 'Michael', 'hq@creativethemes.com', 'https://startersites.io/blocksy/garderobe', '92.115.181.73', '2021-12-23 22:49:27', '2021-12-23 22:49:27', 'Mauris sit amet massa vitae tortor condimentum. Ligula ullamcorper malesuada proin libero nunc. Pharetra pharetra massa massa ultricies mi quis.', 0, '1', '', 'review', 0, 0);
