(11, 1, '2026-03-22 17:23:36', '2026-03-22 17:23:36', '@media (min-width: 691px) and (max-width: 1000px) {\n	.final-sale-home-cta [data-products] {\n		--shop-columns: repeat(3, minmax(0, 1fr))\n	}\n}\n\n.final-sale-home-cta .product {\n	--theme-text-color: rgba(255, 255, 255, 0.5);\n	--theme-heading-color: #fff;\n}', 'blocksy', '', 'inherit', 'closed', 'closed', '', '10-revision-v1', '', '', '2026-03-22 17:23:36', '2026-03-22 17:23:36', '', 10, 'http://localhost:8080/wordpress/?p=11', 0, 'revision', '', 0),
